#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;
struct Pair{int l,r;inline Pair(const int &xx=0,const int &yy=0){l=xx;r=yy;}};
int a[N],n,m,dep[N],cdt,loc[N],ans[N],cnt[N],L,R,Ans,K[N],nQ,idx[N];
vector<int> G[N],dfn[N]; map<string,int> Idx; map<int,Pair> mp[N];
struct node{int l,r,idx;}; vector<node> Q[N];vector<int> D[N];
inline void dfs(const int &u,const int &fa=0)
{
	dfn[dep[u]].push_back(u);loc[u]=int(dfn[dep[u]].size())-1;
	for(int v:G[u])if(v!=fa)dep[v]=dep[u]+1,dfs(v,u);
}
inline int merge(int x,int y)
{
	if(mp[x].size()<mp[y].size()){int t(x);x=y;y=t;}
	for(pair<int,Pair> v:mp[y])
	{
		if(!mp[x].count(v.first))mp[x][v.first]=v.second;
		else
		{
			Pair a=v.second,b=mp[x][v.first],t;
			if(a.l>b.l){t.l=b.l;t.r=a.r;}else t.l=a.l,t.r=b.r;
			mp[x][v.first]=t;
		}
	}
	return x;
}
inline void dfs1(const int &u,const int &fa=0)
{
//	printf("dfs %d\n",u);
	for(int v:G[u])if(v!=fa){dfs1(v,u);idx[u]=merge(idx[u],idx[v]);}
	map<int,Pair> &R=mp[idx[u]];for(int v:D[u])
	{
//		printf("QAQ %d --> %d\n",u,v);
		if(!R.count(K[v]))continue;Pair t=R[K[v]];
		Q[K[v]].push_back((node){t.l,t.r,v});
	}
}
inline void ins(const int &x){Ans+=!(cnt[x]++);} inline void del(const int &x){Ans-=!(--cnt[x]);}
int main()
{
	ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); 
	cin>>n;rep(1,n,i)
	{
		string s;cin>>s;if(Idx.count(s))a[i]=Idx[s];else a[i]=Idx[s]=++m;
		int fa;cin>>fa;G[fa].push_back(i);G[i].push_back(fa);
	}
	dfs(0);cin>>nQ;rep(1,nQ,i){int u;cin>>u>>K[i];K[i]+=dep[u];D[u].push_back(i);}
	rep(1,n,u)mp[idx[u]=u][dep[u]]=Pair(loc[u],loc[u]);dfs1(0);
	rep(0,n,i)if(Q[i].size())
	{
		const int BK=sqrt(Q[i].size())+3;for(int v:dfn[i])cnt[a[v]]=0;
		sort(Q[i].begin(),Q[i].end(),[&](const node&x,const node&y){return x.l/BK==y.l/BK?(((x.l/BK)&1)?x.r>y.r:x.r<y.r):x.l<y.l;});
		L=(*Q[i].begin()).l;R=L-1;Ans=0;for(node v:Q[i])
		{
			while(R<v.r)ins(a[dfn[i][++R]]);while(L>v.l)ins(a[dfn[i][--L]]);
			while(R>v.r)del(a[dfn[i][R--]]);while(L<v.l)del(a[dfn[i][L++]]);
			ans[v.idx]=Ans;
		}
	}
	rep(1,nQ,i)cout<<ans[i]<<'\n';return 0;
}
